import type { Player } from '../types';
import { ResultBuilder, type GameActionResult, type CombatStateChange, type EnemyStateData, type BuffData, type DebuffData } from './ResultBuilder';

export interface Enemy {
    id: string;
    name: string;
    level: number;
    hp: number;
    maxHp: number;
    mp: number;
    maxMp: number;
    atk: number;
    def: number;
    spd: number;
    skills: EnemySkill[];
    drops: EnemyDrop[];
    exp: number;
    gold: number;
    icon: string;
    aiType: 'aggressive' | 'defensive' | 'balanced' | 'support';
}

export interface EnemySkill {
    id: string;
    name: string;
    damage: number;
    mpCost: number;
    type: 'attack' | 'heal' | 'buff' | 'debuff';
    cooldown: number;
    currentCooldown: number;
}

export interface EnemyDrop {
    itemId: string;
    name: string;
    chance: number;
    quantity: [number, number];
}

export interface CombatBuff {
    id: string;
    name: string;
    type: 'buff' | 'debuff';
    stat: 'atk' | 'def' | 'spd' | 'crit';
    value: number;
    duration: number;
    icon: string;
}

export interface CombatLog {
    turn: number;
    actor: 'player' | 'enemy';
    action: string;
    damage?: number;
    heal?: number;
    message: string;
}

export interface CombatState {
    enemy: Enemy;
    turn: number;
    isActive: boolean;
    playerBuffs: CombatBuff[];
    enemyBuffs: CombatBuff[];
    logs: CombatLog[];
    isPlayerTurn: boolean;
    combatStarted: number;
}

export class CombatSystemV2 {
    private static instance: CombatSystemV2;
    private state: CombatState | null = null;
    private player: Player | null = null;
    private playerHpBefore: number = 0;
    private playerMpBefore: number = 0;
    private enemyHpBefore: number = 0;

    private constructor() {}

    static getInstance(): CombatSystemV2 {
        if (!CombatSystemV2.instance) {
            CombatSystemV2.instance = new CombatSystemV2();
        }
        return CombatSystemV2.instance;
    }

    private enemyTemplates: Map<string, Omit<Enemy, 'hp' | 'mp' | 'skills'>> = new Map([
        ['goblin', {
            id: 'goblin', name: '哥布林', level: 1, maxHp: 50, maxMp: 20,
            atk: 8, def: 3, spd: 12, exp: 15, gold: 10, icon: '👺', aiType: 'aggressive',
            drops: [
                { itemId: 'goblin_ear', name: '哥布林耳朵', chance: 0.5, quantity: [1, 2] },
                { itemId: 'rusty_sword', name: '生锈的剑', chance: 0.1, quantity: [1, 1] }
            ]
        }],
        ['wolf', {
            id: 'wolf', name: '灰狼', level: 2, maxHp: 80, maxMp: 0,
            atk: 12, def: 5, spd: 15, exp: 25, gold: 15, icon: '🐺', aiType: 'aggressive',
            drops: [
                { itemId: 'wolf_fang', name: '狼牙', chance: 0.4, quantity: [1, 3] },
                { itemId: 'wolf_pelt', name: '狼皮', chance: 0.3, quantity: [1, 1] }
            ]
        }],
        ['skeleton', {
            id: 'skeleton', name: '骷髅战士', level: 3, maxHp: 100, maxMp: 30,
            atk: 15, def: 8, spd: 8, exp: 40, gold: 25, icon: '💀', aiType: 'balanced',
            drops: [
                { itemId: 'bone', name: '骨头', chance: 0.6, quantity: [1, 3] },
                { itemId: 'old_sword', name: '古旧长剑', chance: 0.15, quantity: [1, 1] }
            ]
        }],
        ['orc', {
            id: 'orc', name: '兽人战士', level: 5, maxHp: 200, maxMp: 50,
            atk: 25, def: 15, spd: 6, exp: 80, gold: 50, icon: '👹', aiType: 'aggressive',
            drops: [
                { itemId: 'orc_tooth', name: '兽人獠牙', chance: 0.5, quantity: [1, 2] },
                { itemId: 'iron_axe', name: '铁斧', chance: 0.2, quantity: [1, 1] }
            ]
        }],
        ['dragon', {
            id: 'dragon', name: '幼龙', level: 10, maxHp: 500, maxMp: 200,
            atk: 50, def: 30, spd: 10, exp: 300, gold: 200, icon: '🐉', aiType: 'balanced',
            drops: [
                { itemId: 'dragon_scale', name: '龙鳞', chance: 0.8, quantity: [1, 3] },
                { itemId: 'dragon_claw', name: '龙爪', chance: 0.3, quantity: [1, 1] },
                { itemId: 'dragon_heart', name: '龙心', chance: 0.05, quantity: [1, 1] }
            ]
        }]
    ]);

    initializeCombat(player: Player, enemyId: string): import('../utils/AIResponseRenderer').AIResponseData {
        const result = this.startCombat(player, enemyId);
        return {
            type: 'combat',
            content: result.message?.content ?? result.message?.title ?? '',
            metadata: {
                timestamp: Date.now()
            },
            combat: {
                playerHP: { current: player.hp ?? 100, max: player.maxHp ?? 100 },
                enemyHP: { current: this.state?.enemy.hp ?? 0, max: this.state?.enemy.maxHp ?? 0 },
                enemyName: this.state?.enemy.name ?? '',
                enemyIcon: this.state?.enemy.icon,
                turn: this.state?.turn ?? 1,
                log: []
            }
        };
    }

    startCombat(player: Player, enemyId: string, level?: number): GameActionResult {
        const template = this.enemyTemplates.get(enemyId);
        if (!template) {
            return new ResultBuilder('combat_attack')
                .setSuccess(false)
                .setMessage('战斗失败', `未知的敌人: ${enemyId}`, 'error', '❌')
                .build();
        }

        const actualLevel = level ?? template.level;
        const levelMultiplier = 1 + (actualLevel - template.level) * 0.2;

        const enemy: Enemy = {
            ...template,
            level: actualLevel,
            hp: Math.floor(template.maxHp * levelMultiplier),
            maxHp: Math.floor(template.maxHp * levelMultiplier),
            mp: Math.floor(template.maxMp * levelMultiplier),
            maxMp: Math.floor(template.maxMp * levelMultiplier),
            atk: Math.floor(template.atk * levelMultiplier),
            def: Math.floor(template.def * levelMultiplier),
            spd: Math.floor(template.spd * levelMultiplier),
            exp: Math.floor(template.exp * levelMultiplier),
            gold: Math.floor(template.gold * levelMultiplier),
            skills: this.getEnemySkills(enemyId, actualLevel)
        };

        this.player = player;
        this.playerHpBefore = player.hp ?? 100;
        this.playerMpBefore = player.mp ?? 50;
        this.enemyHpBefore = enemy.hp;

        this.state = {
            enemy,
            turn: 1,
            isActive: true,
            playerBuffs: [],
            enemyBuffs: [],
            logs: [],
            isPlayerTurn: (player.spd ?? 10) >= enemy.spd,
            combatStarted: Date.now()
        };

        const builder = new ResultBuilder('combat_attack')
            .setMessage('⚔️ 战斗开始', `遭遇 ${enemy.name} (Lv.${enemy.level})！`, 'combat', enemy.icon)
            .setData('enemyId', enemyId)
            .setData('enemyLevel', actualLevel);

        const combatState: CombatStateChange = {
            turn: 1,
            phase: 'combat_start',
            enemy: this.buildEnemyState(enemy, enemy.hp, enemy.mp),
            log: [],
            result: 'ongoing'
        };

        builder.setCombatState(combatState);
        builder.addDetail(`敌人: ${enemy.name} Lv.${enemy.level}`);
        builder.addDetail(`HP: ${enemy.hp}/${enemy.maxHp}`);
        builder.addDetail(`ATK: ${enemy.atk} | DEF: ${enemy.def}`);
        builder.addDetail(`先手: ${this.state.isPlayerTurn ? '玩家' : '敌人'}`);

        return builder.build();
    }

    playerAttack(): GameActionResult {
        if (!this.state || !this.player || !this.state.isPlayerTurn) {
            return this.buildErrorResult('无法行动', '当前不是玩家回合');
        }

        const playerHpBefore = this.player.hp ?? 0;
        const enemyHpBefore = this.state.enemy.hp;

        const baseDamage = this.player.atk ?? 10;
        const critChance = this.player.crit ?? 5;
        const isCrit = Math.random() * 100 < critChance;
        
        let damage = Math.max(1, baseDamage - this.state.enemy.def * 0.5);
        if (isCrit) {
            damage = Math.floor(damage * 1.5);
        }
        damage = Math.floor(damage * (0.9 + Math.random() * 0.2));

        this.state.enemy.hp -= damage;

        const builder = new ResultBuilder('combat_attack')
            .addDamage('玩家', this.state.enemy.name, damage, isCrit);

        if (isCrit) {
            builder.addHighlight('暴击!', '#ff6b6b');
        }

        const enemyState = this.buildEnemyState(this.state.enemy, this.state.enemy.hp, this.state.enemy.mp);

        if (this.state.enemy.hp <= 0) {
            return this.buildVictoryResult(builder, damage);
        }

        this.endPlayerTurn();

        builder.setMessage('⚔️ 攻击', 
            isCrit ? `💥 暴击！对 ${this.state.enemy.name} 造成 ${damage} 点伤害！` : `对 ${this.state.enemy.name} 造成 ${damage} 点伤害`,
            'combat', '⚔️'
        );

        builder.setCombatState({
            turn: this.state.turn,
            phase: 'player_turn',
            playerHp: { before: playerHpBefore, after: this.player.hp ?? 0, max: this.player.maxHp ?? 100 },
            enemy: { ...enemyState, hp: { before: enemyHpBefore, after: this.state.enemy.hp, max: this.state.enemy.maxHp } },
            log: this.buildCombatLog(),
            result: 'ongoing'
        });

        return builder.build();
    }

    playerDefend(): GameActionResult {
        if (!this.state || !this.player || !this.state.isPlayerTurn) {
            return this.buildErrorResult('无法行动', '当前不是玩家回合');
        }

        this.state.playerBuffs.push({
            id: 'defend',
            name: '防御姿态',
            type: 'buff',
            stat: 'def',
            value: 50,
            duration: 1,
            icon: '🛡️'
        });

        this.endPlayerTurn();

        const builder = new ResultBuilder('combat_defend')
            .addShield('玩家', '玩家', 50)
            .setMessage('🛡️ 防御', '摆出防御姿态，防御力提升50%！', 'combat', '🛡️');

        builder.setCombatState({
            turn: this.state.turn,
            phase: 'player_turn',
            playerHp: { before: this.player.hp ?? 0, after: this.player.hp ?? 0, max: this.player.maxHp ?? 100 },
            enemy: this.buildEnemyState(this.state.enemy, this.state.enemy.hp, this.state.enemy.mp),
            log: this.buildCombatLog(),
            result: 'ongoing'
        });

        return builder.build();
    }

    playerUseSkill(skillName: string): GameActionResult {
        if (!this.state || !this.player || !this.state.isPlayerTurn) {
            return this.buildErrorResult('无法行动', '当前不是玩家回合');
        }

        if (!this.player.skills?.includes(skillName)) {
            return this.buildErrorResult('技能失败', '未习得该技能');
        }

        const mpCost = this.getSkillMpCost(skillName);
        if ((this.player.mp ?? 0) < mpCost) {
            return this.buildErrorResult('魔力不足', `需要 ${mpCost} MP，当前只有 ${this.player.mp} MP`);
        }

        const mpBefore = this.player.mp ?? 0;
        this.player.mp = mpBefore - mpCost;

        const baseDamage = this.getSkillDamage(skillName);
        const atkBonus = (this.player.atk ?? 10) * 0.5;
        const damage = Math.floor((baseDamage + atkBonus) * (0.9 + Math.random() * 0.2));

        this.state.enemy.hp -= damage;

        const builder = new ResultBuilder('combat_skill')
            .addManaCost('玩家', '玩家', mpCost)
            .addDamage('玩家', this.state.enemy.name, damage);

        if (this.state.enemy.hp <= 0) {
            return this.buildVictoryResult(builder, damage);
        }

        this.endPlayerTurn();

        builder.setMessage('⚡ 技能', `使用 ${skillName}，造成 ${damage} 点伤害！消耗 ${mpCost} MP`, 'combat', '⚡');
        builder.addDetail(`技能: ${skillName}`);
        builder.addDetail(`伤害: ${damage}`);
        builder.addDetail(`消耗: ${mpCost} MP`);

        builder.setCombatState({
            turn: this.state.turn,
            phase: 'player_turn',
            playerHp: { before: this.playerHpBefore, after: this.player.hp ?? 0, max: this.player.maxHp ?? 100 },
            playerMp: { before: mpBefore, after: this.player.mp ?? 0, max: this.player.maxMp ?? 50 },
            enemy: this.buildEnemyState(this.state.enemy, this.state.enemy.hp, this.state.enemy.mp),
            log: this.buildCombatLog(),
            result: 'ongoing'
        });

        return builder.build();
    }

    playerFlee(): GameActionResult {
        if (!this.state || !this.player || !this.state.isPlayerTurn) {
            return this.buildErrorResult('无法行动', '当前不是玩家回合');
        }

        const fleeChance = 0.3 + (this.player.spd ?? 10) * 0.02 - this.state.enemy.spd * 0.01;
        const success = Math.random() < fleeChance;

        if (success) {
            this.state.isActive = false;
            
            return new ResultBuilder('combat_flee')
                .setMessage('🏃 逃跑成功', '成功逃离战斗！', 'info', '🏃')
                .setCombatState({
                    turn: this.state.turn,
                    phase: 'combat_end',
                    log: this.buildCombatLog(),
                    result: 'fled'
                })
                .build();
        }

        this.endPlayerTurn();

        return new ResultBuilder('combat_flee')
            .setSuccess(false)
            .setMessage('❌ 逃跑失败', '逃跑失败！', 'warning', '❌')
            .setCombatState({
                turn: this.state.turn,
                phase: 'player_turn',
                enemy: this.buildEnemyState(this.state.enemy, this.state.enemy.hp, this.state.enemy.mp),
                log: this.buildCombatLog(),
                result: 'ongoing'
            })
            .build();
    }

    enemyTurn(): GameActionResult {
        if (!this.state || !this.state.isActive || !this.player) {
            return this.buildErrorResult('敌人回合', '战斗未激活');
        }

        const playerHpBefore = this.player.hp ?? 0;
        const action = this.decideEnemyAction();
        let damage = 0;

        const builder = new ResultBuilder('combat_attack');

        switch (action.type) {
            case 'attack':
                damage = this.calculateEnemyDamage(action.skill);
                const defenseBuff = this.state.playerBuffs.find(b => b.stat === 'def');
                if (defenseBuff) {
                    damage = Math.floor(damage * (1 - defenseBuff.value / 100));
                }
                damage = Math.max(1, damage - (this.player?.def ?? 5) * 0.3);
                damage = Math.floor(damage * (0.9 + Math.random() * 0.2));
                
                this.player.hp = Math.max(0, (this.player.hp ?? 0) - damage);
                
                builder.addDamage(this.state.enemy.name, '玩家', damage);
                builder.setMessage(`👹 ${this.state.enemy.name} 攻击`, 
                    `${this.state.enemy.name} 使用 ${action.skill.name}，对你造成 ${damage} 点伤害！`, 
                    'combat', this.state.enemy.icon);
                break;

            case 'buff':
                this.state.enemyBuffs.push({
                    id: action.skill.id,
                    name: action.skill.name,
                    type: 'buff',
                    stat: 'atk',
                    value: 30,
                    duration: 3,
                    icon: '💪'
                });
                builder.addBuff(this.state.enemy.name, this.state.enemy.name, {
                    id: action.skill.id, name: action.skill.name, icon: '💪', stacks: 1, duration: 3, value: 30, description: '攻击力提升'
                });
                builder.setMessage(`💪 ${this.state.enemy.name} 强化`, 
                    `${this.state.enemy.name} 使用 ${action.skill.name}，攻击力提升！`, 
                    'combat', '💪');
                break;

            case 'debuff':
                this.state.playerBuffs.push({
                    id: action.skill.id,
                    name: action.skill.name,
                    type: 'debuff',
                    stat: 'def',
                    value: 20,
                    duration: 2,
                    icon: '😈'
                });
                builder.addDebuff(this.state.enemy.name, '玩家', {
                    id: action.skill.id, name: action.skill.name, icon: '😈', stacks: 1, duration: 2, value: 20, description: '防御力下降'
                });
                builder.setMessage(`😈 ${this.state.enemy.name} 减益`, 
                    `${this.state.enemy.name} 使用 ${action.skill.name}，你的防御力下降！`, 
                    'combat', '😈');
                break;
        }

        if (this.player.hp <= 0) {
            return this.buildDefeatResult(builder, damage);
        }

        this.processBuffDurations('enemy');
        this.state.turn++;
        this.state.isPlayerTurn = true;

        builder.setCombatState({
            turn: this.state.turn,
            phase: 'enemy_turn',
            playerHp: { before: playerHpBefore, after: this.player.hp ?? 0, max: this.player.maxHp ?? 100 },
            enemy: this.buildEnemyState(this.state.enemy, this.state.enemy.hp, this.state.enemy.mp),
            log: this.buildCombatLog(),
            result: 'ongoing'
        });

        return builder.build();
    }

    private buildVictoryResult(builder: ResultBuilder, lastDamage: number): GameActionResult {
        if (!this.state || !this.player) return builder.build();

        this.state.isActive = false;
        const items = this.calculateDrops();

        builder.addExpGain('战斗', this.state.enemy.exp);
        builder.addGoldGain('战斗', this.state.enemy.gold);

        items.forEach(item => {
            builder.addItemGain('战斗', { id: item, name: item, type: 'material', rarity: 'common', icon: '📦', description: '', quantity: 1 });
        });

        builder.setMessage('🏆 战斗胜利', 
            `击败 ${this.state.enemy.name}！获得 ${this.state.enemy.exp} 经验和 ${this.state.enemy.gold} 金币！`, 
            'reward', '🏆');

        if (items.length > 0) {
            builder.addDetail(`掉落物品: ${items.join(', ')}`);
        }

        builder.setCombatState({
            turn: this.state.turn,
            phase: 'combat_end',
            enemy: this.buildEnemyState(this.state.enemy, 0, this.state.enemy.mp),
            log: this.buildCombatLog(),
            result: 'victory'
        });

        builder.setData('rewards', {
            exp: this.state.enemy.exp,
            gold: this.state.enemy.gold,
            items
        });

        return builder.build();
    }

    private buildDefeatResult(builder: ResultBuilder, lastDamage: number): GameActionResult {
        if (!this.state || !this.player) return builder.build();

        this.state.isActive = false;

        builder.setMessage('💀 战斗失败', '你被击败了...', 'error', '💀');

        builder.setCombatState({
            turn: this.state.turn,
            phase: 'combat_end',
            playerHp: { before: this.playerHpBefore, after: 0, max: this.player.maxHp ?? 100 },
            enemy: this.buildEnemyState(this.state.enemy, this.state.enemy.hp, this.state.enemy.mp),
            log: this.buildCombatLog(),
            result: 'defeat'
        });

        return builder.build();
    }

    private buildErrorResult(title: string, message: string): GameActionResult {
        return new ResultBuilder('combat_attack')
            .setSuccess(false)
            .setMessage(title, message, 'error', '❌')
            .build();
    }

    private buildEnemyState(enemy: Enemy, hp: number, mp: number): EnemyStateData {
        return {
            id: enemy.id,
            name: enemy.name,
            hp: { before: enemy.maxHp, after: hp, max: enemy.maxHp },
            mp: { before: enemy.maxMp, after: mp, max: enemy.maxMp },
            shield: 0,
            buffs: this.state?.enemyBuffs.map(b => ({
                id: b.id, name: b.name, icon: b.icon, stacks: 1, duration: b.duration, value: b.value, description: `${b.stat}+${b.value}%`
            })) ?? [],
            debuffs: [],
            isAlive: hp > 0
        };
    }

    private buildCombatLog() {
        return this.state?.logs.map(log => ({
            turn: log.turn,
            phase: log.actor,
            action: log.action,
            actor: log.actor === 'player' ? '玩家' : this.state?.enemy.name ?? '敌人',
            target: log.actor === 'player' ? this.state?.enemy.name ?? '敌人' : '玩家',
            effects: log.damage ? [{ type: 'damage' as const, source: log.actor, target: log.actor === 'player' ? 'enemy' : 'player', value: log.damage, description: log.message }] : [],
            timestamp: Date.now()
        })) ?? [];
    }

    private endPlayerTurn(): void {
        if (!this.state) return;
        this.state.isPlayerTurn = false;
        this.processBuffDurations('player');
    }

    private decideEnemyAction(): { type: 'attack' | 'buff' | 'debuff'; skill: EnemySkill } {
        if (!this.state) {
            return { type: 'attack', skill: { id: 'basic', name: '攻击', damage: 10, mpCost: 0, type: 'attack', cooldown: 0, currentCooldown: 0 } };
        }

        const enemy = this.state.enemy;
        const availableSkills = enemy.skills.filter(s => s.currentCooldown === 0 && s.mpCost <= enemy.mp);

        if (availableSkills.length === 0) {
            return { type: 'attack', skill: { id: 'basic', name: '普通攻击', damage: enemy.atk, mpCost: 0, type: 'attack', cooldown: 0, currentCooldown: 0 } };
        }

        const attackSkills = availableSkills.filter(s => s.type === 'attack');
        if (attackSkills.length > 0) {
            return { type: 'attack', skill: attackSkills[Math.floor(Math.random() * attackSkills.length)] };
        }

        const skill = availableSkills[Math.floor(Math.random() * availableSkills.length)];
        return { type: skill.type as 'attack' | 'buff' | 'debuff', skill };
    }

    private calculateEnemyDamage(skill: EnemySkill): number {
        if (!this.state) return 10;
        let damage = skill.damage || this.state.enemy.atk;
        const atkBuff = this.state.enemyBuffs.find(b => b.stat === 'atk');
        if (atkBuff) damage = Math.floor(damage * (1 + atkBuff.value / 100));
        return damage;
    }

    private processBuffDurations(target: 'player' | 'enemy'): void {
        if (!this.state) return;
        const buffs = target === 'player' ? this.state.playerBuffs : this.state.enemyBuffs;
        for (let i = buffs.length - 1; i >= 0; i--) {
            buffs[i].duration--;
            if (buffs[i].duration <= 0) buffs.splice(i, 1);
        }
    }

    private calculateDrops(): string[] {
        if (!this.state) return [];
        const drops: string[] = [];
        for (const drop of this.state.enemy.drops) {
            if (Math.random() < drop.chance) {
                const quantity = drop.quantity[0] + Math.floor(Math.random() * (drop.quantity[1] - drop.quantity[0] + 1));
                for (let i = 0; i < quantity; i++) drops.push(drop.name);
            }
        }
        return drops;
    }

    private getEnemySkills(enemyId: string, level: number): EnemySkill[] {
        const skillSets: Record<string, EnemySkill[]> = {
            goblin: [
                { id: 'stab', name: '刺击', damage: 10, mpCost: 0, type: 'attack', cooldown: 0, currentCooldown: 0 }
            ],
            wolf: [
                { id: 'bite', name: '撕咬', damage: 15, mpCost: 0, type: 'attack', cooldown: 0, currentCooldown: 0 }
            ],
            skeleton: [
                { id: 'bone_strike', name: '骨击', damage: 20, mpCost: 0, type: 'attack', cooldown: 0, currentCooldown: 0 }
            ],
            orc: [
                { id: 'crush', name: '重击', damage: 35, mpCost: 0, type: 'attack', cooldown: 0, currentCooldown: 0 }
            ],
            dragon: [
                { id: 'flame_breath', name: '火焰吐息', damage: 60, mpCost: 30, type: 'attack', cooldown: 2, currentCooldown: 0 }
            ]
        };
        return (skillSets[enemyId] || []).map(skill => ({ ...skill, damage: Math.floor(skill.damage * (1 + level * 0.1)) }));
    }

    private getSkillMpCost(skillName: string): number {
        const costs: Record<string, number> = { '火球术': 15, '冰霜箭': 12, '闪电链': 20, '治愈术': 10, '盾击': 8, '旋风斩': 15, '背刺': 10, '毒刃': 12 };
        return costs[skillName] ?? 5;
    }

    private getSkillDamage(skillName: string): number {
        const damages: Record<string, number> = { '火球术': 25, '冰霜箭': 20, '闪电链': 30, '治愈术': 0, '盾击': 15, '旋风斩': 20, '背刺': 25, '毒刃': 18 };
        return damages[skillName] ?? 15;
    }

    getState(): CombatState | null { return this.state; }

    getEnemyList(): Array<{ id: string; name: string; level: number; icon: string }> {
        return Array.from(this.enemyTemplates.values()).map(e => ({ id: e.id, name: e.name, level: e.level, icon: e.icon }));
    }
}

export default CombatSystemV2;
